import React from 'react';
import '../styles/LeadCapturePopup.css';

export default function EzDrinkVideoPopup({ isOpen, onClose }) {
  if (!isOpen) return null;
  return (
    <div className="popup-overlay" onClick={onClose} role="presentation">
      <div className="popup-container" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true">
        <button type="button" className="popup-close" onClick={onClose} aria-label="Close">
          ×
        </button>
        <p style={{ color: 'rgba(255,255,255,0.85)' }}>Video is not available right now.</p>
        <button type="button" className="primary-button" onClick={onClose}>
          Close
        </button>
      </div>
    </div>
  );
}
